# ROBUSTNESS PHASE I — NRC format/SID echo, WDBI completeness, SecurityAccess edge cases
# Manually written, not generated by testgen.py. Do not delete.
#
# Covers:
#   TestNRCFormatAndSIDEcho          — resp[1] must equal the triggering SID, len == 3
#   TestWDBICompleteness             — length enforcement, check ordering, response format
#   TestSecurityAccessProtocolEdges  — level mismatch, high sub-fn, fail-count isolation
#
# Run: pytest test_robustness_I_nrc_wdbi_sa.py -v
from __future__ import annotations

import os
import sys

import pytest

sys.path.insert(0, os.path.dirname(__file__))
from conftest import (
    _inline_handle,
    _InlineEcuState,
    _EcuSimulator,
    SID_DIAGNOSTIC_SESSION_CONTROL,
    SID_ECU_RESET,
    SID_READ_DTC_INFO,
    SID_READ_DATA_BY_ID,
    SID_SECURITY_ACCESS,
    SID_WRITE_DATA_BY_ID,
    SID_ROUTINE_CONTROL,
    SID_TESTER_PRESENT,
    SID_NEGATIVE_RESPONSE,
    SESSION_DEFAULT,
    SESSION_EXTENDED,
    NRC_INCORRECT_MSG_LEN,
    NRC_REQUEST_OUT_OF_RANGE,
    NRC_SECURITY_ACCESS_DENIED,
    NRC_INVALID_KEY,
    NRC_SUB_FUNCTION_NOT_SUPPORTED,
    ALGO_SEED_LEN,
    ALGO_KEY_LEN,
    _LEVEL_KEYS,
)

SID_COMMUNICATION_CONTROL = 0x28
SID_CONTROL_DTC_SETTING   = 0x85

NRC_SERVICE_NOT_SUPPORTED_IN_SESSION = 0x7F
NRC_EXCEEDED_NUMBER_OF_ATTEMPTS      = 0x36
NRC_SEQUENCE_ERROR                   = 0x24

DID_VIN        = 0xF190   # read-only, 17 bytes, min_session=default
DID_SPARE_PART = 0xF187   # read+write, 11 bytes, min_session=extended, write_sec=1


def _sim():
    return _InlineEcuState()


def _req(state, pdu):
    return _inline_handle(pdu, state, False)


def _session(state, s):
    _inline_handle(bytes([SID_DIAGNOSTIC_SESSION_CONTROL, s]), state, False)


def _do_cmac_unlock(state, level=1):
    sub_seed = 2 * level - 1
    sub_key  = 2 * level
    resp = _req(state, bytes([SID_SECURITY_ACCESS, sub_seed]))
    if resp is None or resp[0] == SID_NEGATIVE_RESPONSE:
        return False
    seed = bytes(resp[2:])
    key_material = _LEVEL_KEYS.get(level, _LEVEL_KEYS[1])
    key = _EcuSimulator._cmac(key_material, seed)[:ALGO_KEY_LEN]
    resp2 = _req(state, bytes([SID_SECURITY_ACCESS, sub_key]) + key)
    return resp2 is not None and resp2[0] != SID_NEGATIVE_RESPONSE


# ===========================================================================
# TestNRCFormatAndSIDEcho
# ===========================================================================

class TestNRCFormatAndSIDEcho:
    """
    ISO 14229-1 §7.5.2: a negative response PDU is exactly 3 bytes:
      [0x7F, requestSID, NRC_code]
    resp[1] must be the SID of the SERVICE that triggered the NRC —
    not a hardcoded constant, not the previous SID. Verified for every service.
    """

    def _assert_nrc(self, resp, expected_sid, expected_nrc=None):
        assert resp is not None, "Expected NRC response, got None"
        assert len(resp) == 3, f"NRC must be exactly 3 bytes, got {len(resp)}: {resp.hex()}"
        assert resp[0] == SID_NEGATIVE_RESPONSE, f"resp[0] must be 0x7F, got 0x{resp[0]:02X}"
        assert resp[1] == expected_sid, (
            f"resp[1] must echo SID 0x{expected_sid:02X}, got 0x{resp[1]:02X}")
        if expected_nrc is not None:
            assert resp[2] == expected_nrc, (
                f"NRC code: expected 0x{expected_nrc:02X}, got 0x{resp[2]:02X}")

    def test_0x10_dsc_nrc_echoes_sid(self):
        resp = _req(_sim(), bytes([SID_DIAGNOSTIC_SESSION_CONTROL, 0x00]))
        self._assert_nrc(resp, SID_DIAGNOSTIC_SESSION_CONTROL, NRC_SUB_FUNCTION_NOT_SUPPORTED)

    def test_0x11_ecu_reset_nrc_echoes_sid(self):
        resp = _req(_sim(), bytes([SID_ECU_RESET, 0x00]))
        self._assert_nrc(resp, SID_ECU_RESET, NRC_SUB_FUNCTION_NOT_SUPPORTED)

    def test_0x3E_tester_present_nrc_echoes_sid(self):
        resp = _req(_sim(), bytes([SID_TESTER_PRESENT, 0x01]))
        self._assert_nrc(resp, SID_TESTER_PRESENT, NRC_SUB_FUNCTION_NOT_SUPPORTED)

    def test_0x27_security_access_nrc_echoes_sid(self):
        resp = _req(_sim(), bytes([SID_SECURITY_ACCESS, 0x01]))
        self._assert_nrc(resp, SID_SECURITY_ACCESS, NRC_SERVICE_NOT_SUPPORTED_IN_SESSION)

    def test_0x22_rdbi_nrc_echoes_sid(self):
        resp = _req(_sim(), bytes([SID_READ_DATA_BY_ID, 0xDE, 0xAD]))
        self._assert_nrc(resp, SID_READ_DATA_BY_ID, NRC_REQUEST_OUT_OF_RANGE)

    def test_0x2E_wdbi_nrc_echoes_sid(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        resp = _req(s, bytes([SID_WRITE_DATA_BY_ID, 0xDE, 0xAD, 0x00]))
        self._assert_nrc(resp, SID_WRITE_DATA_BY_ID, NRC_REQUEST_OUT_OF_RANGE)

    def test_0x31_routine_control_nrc_echoes_sid(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        resp = _req(s, bytes([SID_ROUTINE_CONTROL, 0x01, 0xAA, 0xBB]))
        self._assert_nrc(resp, SID_ROUTINE_CONTROL, NRC_REQUEST_OUT_OF_RANGE)

    def test_0x28_comm_control_nrc_echoes_sid(self):
        resp = _req(_sim(), bytes([SID_COMMUNICATION_CONTROL, 0x01]))
        self._assert_nrc(resp, SID_COMMUNICATION_CONTROL, NRC_SERVICE_NOT_SUPPORTED_IN_SESSION)

    def test_0x85_control_dtc_nrc_echoes_sid(self):
        resp = _req(_sim(), bytes([SID_CONTROL_DTC_SETTING, 0x01]))
        self._assert_nrc(resp, SID_CONTROL_DTC_SETTING, NRC_SERVICE_NOT_SUPPORTED_IN_SESSION)

    def test_0x19_read_dtc_nrc_echoes_sid(self):
        resp = _req(_sim(), bytes([SID_READ_DTC_INFO, 0xFF]))
        self._assert_nrc(resp, SID_READ_DTC_INFO, NRC_SUB_FUNCTION_NOT_SUPPORTED)

    def test_0x14_clear_dtc_nrc_echoes_sid(self):
        resp = _req(_sim(), bytes([0x14]))  # default session → NRC 0x7F
        self._assert_nrc(resp, 0x14, NRC_SERVICE_NOT_SUPPORTED_IN_SESSION)

    def test_unknown_sid_nrc_echoes_that_sid(self):
        """For unsupported SIDs, resp[1] must echo the unknown SID, not a fixed value."""
        for sid in (0x00, 0x40, 0xAB, 0xFF):
            resp = _req(_sim(), bytes([sid]))
            self._assert_nrc(resp, sid, 0x11)

    def test_nrc_is_always_exactly_3_bytes_across_all_services(self):
        """Parameterized sweep: every NRC from any service is exactly 3 bytes."""
        cases = [
            bytes([SID_DIAGNOSTIC_SESSION_CONTROL, 0x00]),
            bytes([SID_ECU_RESET, 0x00]),
            bytes([SID_TESTER_PRESENT, 0x01]),
            bytes([SID_READ_DATA_BY_ID, 0xDE, 0xAD]),
            bytes([SID_ROUTINE_CONTROL, 0x01, 0xAA, 0xBB]),
            bytes([SID_READ_DTC_INFO, 0xFF]),
            bytes([0x14]),
        ]
        s = _sim(); _session(s, SESSION_EXTENDED)
        for pdu in cases:
            resp = _req(s, pdu)
            if resp is not None and resp[0] == SID_NEGATIVE_RESPONSE:
                assert len(resp) == 3, \
                    f"NRC for {pdu.hex()}: expected 3 bytes, got {len(resp)}: {resp.hex()}"


# ===========================================================================
# TestWDBICompleteness
# ===========================================================================

class TestWDBICompleteness:
    """
    WriteDataByIdentifier (0x2E) check ordering and length enforcement.

    ISO 14229-1 §11.3 requires these checks in order:
      1. PDU length >= 4 (SID + 2 DID bytes + 1 data byte minimum)
      2. DID exists and is writable
      3. Session sufficient
      4. Security level sufficient
      5. Data length exactly matches DID data_length
    """

    def _wdbi(self, state, did, data):
        return _req(state, bytes([SID_WRITE_DATA_BY_ID,
                                   did >> 8, did & 0xFF]) + bytes(data))

    def test_correct_wdbi_succeeds(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        assert _do_cmac_unlock(s, level=1)
        resp = self._wdbi(s, DID_SPARE_PART, bytes(11))
        assert resp is not None and resp[0] == 0x6E

    def test_wdbi_response_is_exactly_3_bytes(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        assert _do_cmac_unlock(s, level=1)
        resp = self._wdbi(s, DID_SPARE_PART, bytes(11))
        assert len(resp) == 3, f"WDBI positive response must be 3 bytes, got {len(resp)}"

    def test_wdbi_response_echoes_did_bytes(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        assert _do_cmac_unlock(s, level=1)
        resp = self._wdbi(s, DID_SPARE_PART, bytes(11))
        assert resp[0] == 0x6E
        assert resp[1] == (DID_SPARE_PART >> 8) and resp[2] == (DID_SPARE_PART & 0xFF)

    def test_data_one_byte_short_returns_nrc_13(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        assert _do_cmac_unlock(s, level=1)
        resp = self._wdbi(s, DID_SPARE_PART, bytes(10))  # 11 - 1
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_INCORRECT_MSG_LEN

    def test_data_one_byte_long_returns_nrc_13(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        assert _do_cmac_unlock(s, level=1)
        resp = self._wdbi(s, DID_SPARE_PART, bytes(12))  # 11 + 1
        assert resp is not None and resp[2] == NRC_INCORRECT_MSG_LEN

    def test_data_zero_bytes_returns_nrc_13(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        assert _do_cmac_unlock(s, level=1)
        resp = self._wdbi(s, DID_SPARE_PART, b'')
        assert resp is not None and resp[2] == NRC_INCORRECT_MSG_LEN

    def test_pdu_under_4_bytes_returns_nrc_13(self):
        resp = _req(_sim(), bytes([SID_WRITE_DATA_BY_ID, 0xF1]))  # only 2 bytes total
        assert resp is not None and resp[2] == NRC_INCORRECT_MSG_LEN

    def test_write_to_read_only_did_returns_nrc_31(self):
        """VIN is read-only (access_write=False) — WDBI must return NRC 0x31."""
        s = _sim(); _session(s, SESSION_EXTENDED)
        assert _do_cmac_unlock(s, level=1)
        resp = self._wdbi(s, DID_VIN, bytes(17))
        assert resp is not None and resp[2] == NRC_REQUEST_OUT_OF_RANGE

    def test_write_unknown_did_returns_nrc_31(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        resp = self._wdbi(s, 0xDEAD, bytes(4))
        assert resp is not None and resp[2] == NRC_REQUEST_OUT_OF_RANGE

    def test_session_gate_checked_before_security_gate(self):
        """Wrong session → NRC 0x7F, even if security would also fail."""
        s = _sim()  # default session, no security unlock
        resp = self._wdbi(s, DID_SPARE_PART, bytes(11))
        assert resp is not None and resp[2] == NRC_SERVICE_NOT_SUPPORTED_IN_SESSION, \
            "Session gate must fire before security gate"

    def test_security_gate_checked_before_length_gate(self):
        """Right session, no unlock → NRC 0x33, even if length would also be wrong."""
        s = _sim(); _session(s, SESSION_EXTENDED)
        # send wrong length AND no unlock — must get security NRC, not length NRC
        resp = self._wdbi(s, DID_SPARE_PART, bytes(5))
        assert resp is not None and resp[2] == NRC_SECURITY_ACCESS_DENIED, \
            "Security gate must fire before length gate"

    def test_length_gate_is_last_check(self):
        """All other checks pass → wrong length → NRC 0x13."""
        s = _sim(); _session(s, SESSION_EXTENDED)
        assert _do_cmac_unlock(s, level=1)
        resp = self._wdbi(s, DID_SPARE_PART, bytes(7))
        assert resp is not None and resp[2] == NRC_INCORRECT_MSG_LEN


# ===========================================================================
# TestSecurityAccessProtocolEdges
# ===========================================================================

class TestSecurityAccessProtocolEdges:
    """
    SecurityAccess edge cases not covered by Phase C or Phase G:
    level mismatch, high sub-function (level 128), fail-count per-level isolation.
    """

    def test_level_mismatch_seed_l1_key_l2_returns_nrc_24(self):
        """Request seed for level 1 (sub=0x01) then try to send key for level 2 (sub=0x04)."""
        s = _sim(); _session(s, SESSION_EXTENDED)
        _req(s, bytes([SID_SECURITY_ACCESS, 0x01]))  # seed for L1
        resp = _req(s, bytes([SID_SECURITY_ACCESS, 0x04]) + bytes(ALGO_KEY_LEN))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_SEQUENCE_ERROR, \
            f"Level mismatch (seed L1, key L2): expected NRC 0x24, got 0x{resp[2]:02X}"

    def test_sub_ff_requests_seed_for_level_128(self):
        """Sub=0xFF is odd → requestSeed for level 128. Must return a seed, not NRC."""
        s = _sim(); _session(s, SESSION_EXTENDED)
        resp = _req(s, bytes([SID_SECURITY_ACCESS, 0xFF]))
        assert resp is not None and resp[0] == 0x67, \
            f"Sub=0xFF (level 128): expected seed response 0x67, got {resp!r}"
        assert len(resp) == 2 + ALGO_SEED_LEN

    def test_pending_seed_cleared_after_successful_unlock(self):
        """After a successful unlock, pending_seed and pending_level must be None."""
        s = _sim(); _session(s, SESSION_EXTENDED)
        assert _do_cmac_unlock(s, level=1)
        assert s.pending_seed is None
        assert s.pending_level is None

    def test_after_one_wrong_key_can_request_new_seed(self):
        """One wrong key increments fail count but does not lock out — new seed allowed."""
        s = _sim(); _session(s, SESSION_EXTENDED)
        _req(s, bytes([SID_SECURITY_ACCESS, 0x01]))  # requestSeed
        _req(s, bytes([SID_SECURITY_ACCESS, 0x02]) + bytes(ALGO_KEY_LEN))  # wrong key
        resp = _req(s, bytes([SID_SECURITY_ACCESS, 0x01]))  # new seed request
        assert resp is not None and resp[0] == 0x67, \
            "After 1 wrong key, requestSeed must still succeed"

    def test_after_one_wrong_key_correct_key_succeeds(self):
        """Fail count = 1; sending correct key on next attempt clears it and grants access."""
        s = _sim(); _session(s, SESSION_EXTENDED)
        _req(s, bytes([SID_SECURITY_ACCESS, 0x01]))
        _req(s, bytes([SID_SECURITY_ACCESS, 0x02]) + bytes(ALGO_KEY_LEN))  # wrong key
        ok = _do_cmac_unlock(s, level=1)
        assert ok, "Correct key after 1 wrong attempt must succeed"

    def test_fail_count_is_per_level_l1_failure_does_not_affect_l2(self):
        """3 wrong L1 keys locks out L1 but L2 must still accept a seed request."""
        s = _sim(); _session(s, SESSION_EXTENDED)
        for _ in range(3):
            _req(s, bytes([SID_SECURITY_ACCESS, 0x01]))  # seed L1
            _req(s, bytes([SID_SECURITY_ACCESS, 0x02]) + bytes(ALGO_KEY_LEN))  # wrong
        # L1 is now locked out
        lock_resp = _req(s, bytes([SID_SECURITY_ACCESS, 0x01]))
        assert lock_resp is not None and lock_resp[2] == NRC_EXCEEDED_NUMBER_OF_ATTEMPTS
        # L2 must still accept a seed request
        l2_resp = _req(s, bytes([SID_SECURITY_ACCESS, 0x03]))
        assert l2_resp is not None and l2_resp[0] == 0x67, \
            "L1 lockout must not affect L2 seed request"

    def test_l1_unlock_does_not_set_l2_unlocked(self):
        """Unlocking L1 must leave L2 locked."""
        s = _sim(); _session(s, SESSION_EXTENDED)
        assert _do_cmac_unlock(s, level=1)
        assert s.sec_unlocked.get(1) is True
        assert not s.sec_unlocked.get(2), "L1 unlock must not grant L2 access"

    def test_independent_state_objects_share_no_state(self):
        """Two _InlineEcuState instances must be fully independent."""
        s1 = _sim(); _session(s1, SESSION_EXTENDED); _do_cmac_unlock(s1, level=1)
        s2 = _sim()  # fresh state
        assert not s2.sec_unlocked.get(1), "s2 must not inherit s1's security unlock"
        assert s2.session == SESSION_DEFAULT, "s2 session must be default, not s1's extended"

    def test_double_seed_request_replaces_pending_seed(self):
        """Second requestSeed before sendKey must replace the first seed (not accumulate)."""
        s = _sim(); _session(s, SESSION_EXTENDED)
        r1 = _req(s, bytes([SID_SECURITY_ACCESS, 0x01]))
        seed1 = bytes(r1[2:])
        r2 = _req(s, bytes([SID_SECURITY_ACCESS, 0x01]))
        seed2 = bytes(r2[2:])
        # The second seed is now active; compute key for seed2 and verify it works
        key_material = _LEVEL_KEYS[1]
        key2 = _EcuSimulator._cmac(key_material, seed2)[:ALGO_KEY_LEN]
        resp = _req(s, bytes([SID_SECURITY_ACCESS, 0x02]) + key2)
        assert resp is not None and resp[0] == 0x67 and resp[0] != SID_NEGATIVE_RESPONSE, \
            "Key derived from second seed must succeed"
